#!/usr/bin/env python3
"""
CI/CD dependency installation script.

Installs requirements with hash verification for supply chain security.
Uses --upgrade to ensure latest compatible versions per constraints.
"""

import subprocess
import sys
import os


def validate_requirements_file(filepath):
    """Validate that the requirements file exists and has reasonable content."""
    if not os.path.isfile(filepath):
        print(f"ERROR: Requirements file not found: {filepath}")
        sys.exit(1)

    # Resolve to absolute path to prevent path traversal
    abs_path = os.path.realpath(filepath)
    expected_dir = os.path.realpath(os.getcwd())
    if not abs_path.startswith(expected_dir):
        print("ERROR: Requirements file must be within the project directory.")
        sys.exit(1)

    # Check file is not empty
    if os.path.getsize(filepath) == 0:
        print("ERROR: Requirements file is empty.")
        sys.exit(1)

    # Basic validation of file contents
    with open(filepath, "r") as f:
        for line_num, line in enumerate(f, 1):
            stripped = line.strip()
            if not stripped or stripped.startswith("#"):
                continue
            # Warn if no hash pinning is present (but don't block)
            if "--hash" not in stripped and "==" not in stripped:
                print(
                    f"WARNING: Line {line_num} has no version pin: {stripped}"
                )
                print(
                    "  Consider pinning versions with == and adding --hash for "
                    "supply chain security."
                )

    return abs_path


def install_requirements(requirements_file="requirements.txt"):
    """
    Install requirements securely.

    Uses hash verification (--require-hashes) when hashes are present in the
    requirements file. This protects against supply chain attacks by verifying
    package integrity.

    Note: While skipping hash verification may seem faster, the security risk
    in CI/CD pipelines is significant. Hash verification adds minimal overhead
    compared to actual download/install time.
    """
    filepath = validate_requirements_file(requirements_file)

    # Check if requirements file contains hashes
    has_hashes = False
    with open(filepath, "r") as f:
        for line in f:
            if "--hash" in line:
                has_hashes = True
                break

    # Build pip command
    pip_cmd = [
        sys.executable,
        "-m",
        "pip",
        "install",
        "--upgrade",
        "-r",
        filepath,
    ]

    if has_hashes:
        # When hashes are present, pip automatically enforces --require-hashes
        print("Hash verification enabled - verifying package integrity.")
    else:
        print(
            "WARNING: No hashes found in requirements file. "
            "Consider adding hashes for supply chain security."
        )
        print(
            "  Generate hashes with: pip-compile --generate-hashes requirements.in"
        )
        print(
            "  Or use: pip hash <package-file> to get hashes for individual packages."
        )

    # Use --no-cache-dir in CI to avoid cache poisoning between builds
    # (optional, uncomment if desired)
    # pip_cmd.append("--no-cache-dir")

    print(f"Running: {' '.join(pip_cmd)}")

    try:
        result = subprocess.run(
            pip_cmd,
            check=True,
            capture_output=True,
            text=True,
            timeout=600,  # 10 minute timeout
        )
        print(result.stdout)
        if result.stderr:
            # Print stderr but don't fail - pip often writes warnings to stderr
            print(f"pip stderr output:\n{result.stderr}")
        print("Dependencies installed successfully.")
        return 0

    except subprocess.TimeoutExpired:
        print("ERROR: pip install timed out after 600 seconds.")
        return 1
    except subprocess.CalledProcessError as e:
        print(f"ERROR: pip install failed with return code {e.returncode}")
        if e.stdout:
            print(f"stdout:\n{e.stdout}")
        if e.stderr:
            print(f"stderr:\n{e.stderr}")
        return e.returncode


def main():
    """Main entry point for CI/CD dependency installation."""
    # Upgrade pip itself first
    print("Upgrading pip...")
    try:
        subprocess.run(
            [sys.executable, "-m", "pip", "install", "--upgrade", "pip"],
            check=True,
            capture_output=True,
            text=True,
            timeout=120,
        )
    except (subprocess.CalledProcessError, subprocess.TimeoutExpired) as e:
        print(f"WARNING: Failed to upgrade pip: {e}")

    # Determine requirements file
    req_file = os.environ.get("REQUIREMENTS_FILE", "requirements.txt")

    # Sanitize: only allow simple filenames, no path separators for env var input
    if os.sep in req_file or (os.altsep and os.altsep in req_file):
        # Allow only if it's a relative path within the project
        pass  # validate_requirements_file will check path traversal

    exit_code = install_requirements(req_file)
    sys.exit(exit_code)


if __name__ == "__main__":
    main()